parameters.jsCode:
let text = $json["content"]["parts"][0]["text"];

// Strip markdown fences if present
text = text.replace(/```json\s*/gi, "").replace(/```/g, "").trim();

try {
  return [{ json: JSON.parse(text) }];
} catch (e) {
  return [{ json: { error: "Invalid JSON returned", raw_output: text } }];
}
